import { Layout, notification } from "antd";
import "antd/dist/antd.css";
import { pipe } from "fp-ts/lib/function";
import * as TE from "fp-ts/lib/TaskEither";
import "geoportal-extensions-leaflet/dist/GpPluginLeaflet";
import "geoportal-extensions-leaflet/dist/GpPluginLeaflet.css";
import { LatLngTuple } from "leaflet";
import React, { useCallback, useEffect, useRef, useState } from "react";
import { Map, Marker, Polyline } from "react-leaflet";
import { DisplayedLayers } from "../App";
import { getFlightData, GpsRecord } from "../flightData";
import { AltitudeChart } from "./AltitudeChart";
import { Chart } from "./CustomChart";
import { OaciLayer, OpenStreetMapLayer } from "./layer";
import LocateControl from "./LocateControl";

const { Footer } = Layout;
const defaultLatLng: LatLngTuple = [43.5, 3.95];
const zoom: number = 11;

type LeafletMapProps = {
  displayLFMT: boolean;
  displayedLayers: DisplayedLayers;
};

export const LeafletMap = ({
  displayLFMT,
  displayedLayers,
}: LeafletMapProps) => {
  const [gpsRecords, setLines] = useState<GpsRecord[] | null>(null);
  const [mapLoaded, setMapLoaded] = useState<boolean>(false);
  const [currentPoint, setCurrentPoint] = useState<number | null>(null);
  // const mapRef = useRef<LeafletInternalMap>(null);
  const [mapRef, setMapRef] = useState<Map | null>(null);
  const onRefChange = useCallback((node) => {
    // ref value changed to node
    setMapRef(node); // e.g. change ref state to trigger re-render
    if (node === null) {
      // node is null, if DOM node of ref had been unmounted before
    } else {
      // ref value exists
      setMapLoaded(true);
    }
  }, []);

  const pathRef = useRef<Polyline>(null);
  const openNotificationWithIcon = ({
    title,
    message,
  }: {
    title: string;
    message: string;
  }) => {
    notification["warning"]({
      message: title,
      description: message,
    });
  };

  useEffect(() => {
    pipe(
      getFlightData({ file: "20201019-164100.txt", start: 800, end: 3500 }),
      // getFlightData({ file: "20191218-181314.txt" }),
      // getFlightData("flight1.txt"),
      TE.fold(
        (e) => async () => {
          console.error(e);
          if (e instanceof Error) {
            console.error(e);
            openNotificationWithIcon({ title: "Error", message: e.message });
          }
        },
        (row) => async () => {
          setLines(row);
        },
      ),
    )();
  }, []);
  const leafletMap = mapRef?.leafletElement;
  const currentGpsRecord =
    currentPoint && gpsRecords ? gpsRecords[currentPoint] : null;
  return (
    <>
      <Layout>
        <Map id="mapId" ref={onRefChange} center={defaultLatLng} zoom={zoom}>
          {displayedLayers.open_street_map && <OpenStreetMapLayer />}
          {displayedLayers.icao && <OaciLayer />}
          {displayLFMT && leafletMap && <Chart map={leafletMap} />}
          <LocateControl startDirectly={false} />
          {gpsRecords && (
            <Polyline
              ref={pathRef}
              opacity={10}
              color="black"
              positions={gpsRecords.map(
                (record) => [record.latitude, record.longitude] as LatLngTuple,
              )}
              className={"onTop"}
            />
          )}
          {currentGpsRecord && (
            <Marker
              // icon={}
              position={{
                lat: currentGpsRecord.latitude,
                lng: currentGpsRecord.longitude,
              }}
            />
          )}
        </Map>
        <div style={{ height: "20vh" }}>
          {gpsRecords && (
            <AltitudeChart
              gpsRecordArray={gpsRecords}
              onNearestX={({ x }) => {
                console.log(x);
                return setCurrentPoint(x);
              }}
            />
          )}
        </div>
      </Layout>
    </>
  );
};
